   153→  static void Spawn(const FunctionCallbackInfo<Value>& args) {
   154→    Environment* env = Environment::GetCurrent(args);
   155→    Local<Context> context = env->context();
   156→    ProcessWrap* wrap;
   157→    ASSIGN_OR_RETURN_UNWRAP(&wrap, args.This());
   158→    THROW_IF_INSUFFICIENT_PERMISSIONS(
   159→        env, permission::PermissionScope::kChildProcess, "");
   160→    int err = 0;
   161→
   162→    Local<Object> js_options =
   163→        args[0]->ToObject(env->context()).ToLocalChecked();
   164→
   165→    uv_process_options_t options;
   166→    memset(&options, 0, sizeof(uv_process_options_t));
   167→
   168→    options.exit_cb = OnExit;
   169→
   170→    // options.uid
   171→    Local<Value> uid_v =
   172→        js_options->Get(context, env->uid_string()).ToLocalChecked();
   173→    if (!uid_v->IsUndefined() && !uid_v->IsNull()) {
   174→      CHECK(uid_v->IsInt32());
   175→      const int32_t uid = uid_v.As<Int32>()->Value();
   176→      options.flags |= UV_PROCESS_SETUID;
   177→      options.uid = static_cast<uv_uid_t>(uid);
   178→    }
   179→
   180→    // options.gid
   181→    Local<Value> gid_v =
   182→        js_options->Get(context, env->gid_string()).ToLocalChecked();
   183→    if (!gid_v->IsUndefined() && !gid_v->IsNull()) {
   184→      CHECK(gid_v->IsInt32());
   185→      const int32_t gid = gid_v.As<Int32>()->Value();
   186→      options.flags |= UV_PROCESS_SETGID;
   187→      options.gid = static_cast<uv_gid_t>(gid);
   188→    }
   189→
   190→    // TODO(bnoordhuis) is this possible to do without mallocing ?
   191→
   192→    // options.file
   193→    Local<Value> file_v =
   194→        js_options->Get(context, env->file_string()).ToLocalChecked();
   195→    CHECK(file_v->IsString());
   196→    node::Utf8Value file(env->isolate(), file_v);
   197→    options.file = *file;
   198→
   199→    // Undocumented feature of Win32 CreateProcess API allows spawning
   200→    // batch files directly but is potentially insecure because arguments
   201→    // are not escaped (and sometimes cannot be unambiguously escaped),
   202→    // hence why they are rejected here.
   203→#ifdef _WIN32
   204→    if (IsWindowsBatchFile(options.file))
   205→      err = UV_EINVAL;
   206→#endif
   207→
   208→    // options.args
   209→    Local<Value> argv_v =
   210→        js_options->Get(context, env->args_string()).ToLocalChecked();
   211→    if (!argv_v.IsEmpty() && argv_v->IsArray()) {
   212→      Local<Array> js_argv = argv_v.As<Array>();
   213→      int argc = js_argv->Length();
   214→      CHECK_LT(argc, INT_MAX);  // Check for overflow.
   215→
   216→      // Heap allocate to detect errors. +1 is for nullptr.
   217→      options.args = new char*[argc + 1];
   218→      for (int i = 0; i < argc; i++) {
   219→        node::Utf8Value arg(env->isolate(),
   220→                            js_argv->Get(context, i).ToLocalChecked());
   221→        options.args[i] = strdup(*arg);
   222→        CHECK_NOT_NULL(options.args[i]);
   223→      }
   224→      options.args[argc] = nullptr;
   225→    }
   226→
   227→    // options.cwd
   228→    Local<Value> cwd_v =
   229→        js_options->Get(context, env->cwd_string()).ToLocalChecked();
   230→    node::Utf8Value cwd(env->isolate(),
   231→                        cwd_v->IsString() ? cwd_v : Local<Value>());
   232→    if (cwd.length() > 0) {
   233→      options.cwd = *cwd;
   234→    }
   235→
   236→    // options.env
   237→    Local<Value> env_v =
   238→        js_options->Get(context, env->env_pairs_string()).ToLocalChecked();
   239→    if (!env_v.IsEmpty() && env_v->IsArray()) {
   240→      Local<Array> env_opt = env_v.As<Array>();
   241→      int envc = env_opt->Length();
   242→      CHECK_LT(envc, INT_MAX);            // Check for overflow.
   243→      options.env = new char*[envc + 1];  // Heap allocated to detect errors.
   244→      for (int i = 0; i < envc; i++) {
   245→        node::Utf8Value pair(env->isolate(),
   246→                             env_opt->Get(context, i).ToLocalChecked());
   247→        options.env[i] = strdup(*pair);
   248→        CHECK_NOT_NULL(options.env[i]);
   249→      }
   250→      options.env[envc] = nullptr;
   251→    }
   252→
   253→    // options.stdio
   254→    ParseStdioOptions(env, js_options, &options);
   255→
   256→    // options.windowsHide
   257→    Local<Value> hide_v =
   258→        js_options->Get(context, env->windows_hide_string()).ToLocalChecked();
   259→
   260→    if (hide_v->IsTrue()) {
   261→      options.flags |= UV_PROCESS_WINDOWS_HIDE;
   262→    }
   263→
   264→    if (env->hide_console_windows()) {
   265→      options.flags |= UV_PROCESS_WINDOWS_HIDE_CONSOLE;
   266→    }
   267→
   268→    // options.windows_verbatim_arguments
   269→    Local<Value> wva_v =
   270→        js_options->Get(context, env->windows_verbatim_arguments_string())
   271→            .ToLocalChecked();
   272→
   273→    if (wva_v->IsTrue()) {
   274→      options.flags |= UV_PROCESS_WINDOWS_VERBATIM_ARGUMENTS;
   275→    }
   276→
   277→    // options.detached
   278→    Local<Value> detached_v =
   279→        js_options->Get(context, env->detached_string()).ToLocalChecked();
   280→
   281→    if (detached_v->IsTrue()) {
   282→      options.flags |= UV_PROCESS_DETACHED;
   283→    }
   284→
   285→    if (err == 0) {
   286→      err = uv_spawn(env->event_loop(), &wrap->process_, &options);
   287→      wrap->MarkAsInitialized();
   288→    }
   289→
   290→    if (err == 0) {
   291→      CHECK_EQ(wrap->process_.data, wrap);
   292→      wrap->object()->Set(context, env->pid_string(),
   293→                          Integer::New(env->isolate(),
   294→                                       wrap->process_.pid)).Check();
   295→    }
   296→
   297→    if (options.args) {
   298→      for (int i = 0; options.args[i]; i++) free(options.args[i]);
   299→      delete [] options.args;
   300→    }
   301→
   302→    if (options.env) {
   303→      for (int i = 0; options.env[i]; i++) free(options.env[i]);
   304→      delete [] options.env;
   305→    }
   306→
   307→    delete[] options.stdio;
   308→
   309→    args.GetReturnValue().Set(err);
   310→  }
   311→
   312→  static void Kill(const FunctionCallbackInfo<Value>& args) {
   313→    Environment* env = Environment::GetCurrent(args);
   314→    ProcessWrap* wrap;
   315→    ASSIGN_OR_RETURN_UNWRAP(&wrap, args.This());
   316→    int signal = args[0]->Int32Value(env->context()).FromJust();
   317→#ifdef _WIN32
   318→    if (signal != SIGKILL && signal != SIGTERM && signal != SIGINT &&
   319→        signal != SIGQUIT) {
   320→      signal = SIGKILL;
   321→    }
   322→#endif
   323→    int err = uv_process_kill(&wrap->process_, signal);
   324→    args.GetReturnValue().Set(err);
   325→  }
   326→
   327→  static void OnExit(uv_process_t* handle,
   328→                     int64_t exit_status,
   329→                     int term_signal) {
   330→    ProcessWrap* wrap = ContainerOf(&ProcessWrap::process_, handle);
   331→    CHECK_EQ(&wrap->process_, handle);
   332→
   333→    Environment* env = wrap->env();
   334→    HandleScope handle_scope(env->isolate());
